/**
 * ngram-draft.test.ts — the prompt-lookup / n-gram draft is correct, and the
 * speculative-decode LOOP it drives is lossless-equivalent to greedy baseline.
 *
 * Two layers of test:
 *   1. ngramDraft pure-function behavior (longest-suffix match, K cap, no-match
 *      fallback, recency).
 *   2. An end-to-end loop equivalence test against a DETERMINISTIC oracle "model"
 *      (a fixed next-token function). It runs (a) the plain greedy baseline and
 *      (b) the speculative loop (ngramDraft + an oracle verify mirroring the Rust
 *      `inner_verify_batch` accept rule) and asserts byte-identical output plus
 *      accepted > 0 on a repetitive sequence. This is the host-side analogue of
 *      the Rust `ngram_speculative_decode_matches_greedy_baseline` test.
 */

import { describe, expect, it } from 'vitest';
import { ngramDraft, ngramDraftWithMatch } from './ngram-draft';

describe('ngramDraftWithMatch (match-length for the cost gate)', () => {
  it('reports the suffix match LENGTH that produced the draft', () => {
    // longest reused suffix "1 2 3" is a 3-gram → matchLen 3.
    const r = ngramDraftWithMatch([9, 1, 2, 3, 7, 7, 7, 1, 2, 3], {
      k: 2,
      nMax: 3,
    });
    expect(r.matchLen).toBe(3);
    expect(r.draft[0]).toBe(7);
  });

  it('reports a SHORT match length for a weak (1-gram) recurrence', () => {
    // Only the single token "1" recurs (no longer suffix) → matchLen 1 (weak;
    // the cost gate suppresses drafting below MESH_SPEC_DECODE_MIN_MATCH).
    const r = ngramDraftWithMatch([1, 5, 6, 7, 1], { k: 2, nMax: 3 });
    expect(r.matchLen).toBe(1);
  });

  it('matchLen is 0 when nothing recurs (caller falls back to 1-token step)', () => {
    const r = ngramDraftWithMatch([5, 6, 7, 8, 9], { k: 4, nMax: 3 });
    expect(r).toEqual({ draft: [], matchLen: 0 });
  });
});

describe('ngramDraft (prompt-lookup)', () => {
  it('proposes the continuation of the longest recurring suffix', () => {
    // "1 2 3 1 2 3 1 2": longest reused suffix is "1 2" (n=2) whose earlier
    // occurrences are followed by "3 1 2 ...".
    const draft = ngramDraft([1, 2, 3, 1, 2, 3, 1, 2], { k: 4, nMax: 3 });
    expect(draft[0]).toBe(3);
  });

  it('prefers the LONGEST matching suffix over shorter ones', () => {
    // Suffix "...a b c" recurs as a 3-gram; the draft must follow the 3-gram
    // match, not a shorter 1-gram coincidence.
    const seq = [9, 1, 2, 3, 7, 7, 7, 1, 2, 3];
    const draft = ngramDraft(seq, { k: 2, nMax: 3 });
    // longest suffix "1 2 3" recurs at index 1, followed by 7.
    expect(draft[0]).toBe(7);
  });

  it('caps the draft at K tokens', () => {
    const seq = [1, 2, 1, 2, 3, 4, 5, 6, 7, 1, 2];
    const draft = ngramDraft(seq, { k: 3, nMax: 2 });
    expect(draft.length).toBeLessThanOrEqual(3);
  });

  it('returns empty when no suffix recurs (novel tail → baseline fallback)', () => {
    expect(ngramDraft([5, 6, 7, 8, 9], { k: 4, nMax: 3 })).toEqual([]);
  });

  it('returns empty for empty sequence or K=0', () => {
    expect(ngramDraft([], { k: 4 })).toEqual([]);
    expect(ngramDraft([1, 2, 1], { k: 0 })).toEqual([]);
  });

  it('uses the most RECENT earlier occurrence when a suffix recurs twice', () => {
    // suffix "1" recurs at idx 0 (→2) and idx 2 (→9). Recency picks idx 2 → 9.
    const seq = [1, 2, 1, 9, 1];
    const draft = ngramDraft(seq, { k: 1, nMax: 1 });
    expect(draft).toEqual([9]);
  });
});

// ── Deterministic oracle "model": a fixed next-token function. ───────────────
// nextToken(history) returns the greedy argmax token the model would emit after
// `history`. We use a simple repeating generator so the n-gram draft finds
// matches (acceptance > 0) while still being a real autoregressive function.
function oracleNextToken(history: readonly number[]): number {
  // Period-5 cycle keyed on the last token, with a deterministic twist so it is
  // not trivially constant: next = (lastTok * 3 + len) mod 5, then mapped to a
  // small vocab. This yields long repeating runs once the cycle locks in.
  const last = history[history.length - 1] ?? 0;
  return (last * 3 + 1) % 5;
}

/** Plain greedy baseline: argmax oracle, one token per step. */
function greedyBaseline(prompt: number[], maxNew: number): number[] {
  const seq = [...prompt];
  const out: number[] = [];
  for (let i = 0; i < maxNew; i++) {
    const t = oracleNextToken(seq);
    seq.push(t);
    out.push(t);
  }
  return out;
}

/**
 * Speculative loop mirroring the host path: ngramDraft → oracle "verify-batch".
 * The oracle verify accepts candidate[i] iff it equals oracleNextToken(seq so
 * far) — EXACTLY the Rust `inner_verify_batch` greedy accept rule (cand ==
 * argmax). On first mismatch it emits the oracle's own token (the correction);
 * on full accept it emits the continuation. This is what `/verify-batch` returns
 * as { accepted, next_token }.
 */
function speculativeLoop(
  prompt: number[],
  maxNew: number,
): { out: number[]; totalAccepted: number } {
  const seq = [...prompt];
  const out: number[] = [];
  let totalAccepted = 0;
  while (out.length < maxNew) {
    const budget = maxNew - out.length;
    // Mirror the host loop: draft, clamp to budget-1 (verify always also emits
    // nextToken), then oracle verify-batch. Empty draft = single greedy step.
    const cand = ngramDraft(seq, { k: 4, nMax: 3 }).slice(
      0,
      Math.max(0, budget - 1),
    );
    // Oracle verify-batch: walk candidates, accept longest argmax-matching prefix.
    const accepted: number[] = [];
    const scratch = [...seq];
    let nextToken = -1;
    for (let i = 0; i < cand.length; i++) {
      const target = oracleNextToken(scratch);
      if (cand[i] === target) {
        accepted.push(cand[i]!);
        scratch.push(cand[i]!);
      } else {
        nextToken = target; // correction
        break;
      }
    }
    if (nextToken === -1) {
      // full accept (or empty draft) → continuation token after the prefix.
      nextToken = oracleNextToken(scratch);
    }
    totalAccepted += accepted.length;
    for (const t of accepted) {
      seq.push(t);
      out.push(t);
    }
    seq.push(nextToken);
    out.push(nextToken);
  }
  out.length = maxNew;
  return { out, totalAccepted };
}

describe('n-gram speculative decode loop (lossless greedy equivalence)', () => {
  it('emits byte-identical tokens to the greedy baseline, accepting > 0 on a repetitive seq', () => {
    const prompt = [3, 1, 4, 1, 5, 3, 1, 4, 1, 5]; // repetitive seed
    const maxNew = 40;
    const baseline = greedyBaseline(prompt, maxNew);
    const spec = speculativeLoop(prompt, maxNew);
    expect(spec.out).toEqual(baseline);
    expect(spec.totalAccepted).toBeGreaterThan(0);
  });

  it('is identical even when the draft never matches (degenerate → pure baseline)', () => {
    // A strictly-increasing prompt with a verify oracle the draft cannot predict
    // still produces baseline output (every step falls back to one greedy step).
    const prompt = [0, 1, 2];
    const maxNew = 12;
    const baseline = greedyBaseline(prompt, maxNew);
    const spec = speculativeLoop(prompt, maxNew);
    expect(spec.out).toEqual(baseline);
  });
});
